// Autentica o chamador e filtra: só segue avaliação com nota <= 2.
// O Database Webhook do Supabase envia { type: 'INSERT', record: {...} }
// e o header x-webhook-secret configurado lá.
const headers = $json.headers || {};
if (headers['x-webhook-secret'] !== $env.SUPABASE_WEBHOOK_SECRET) {
  return []; // secret errado — descarta silenciosamente
}

const body = $json.body || {};
const record = body.record || {};
if (body.type !== 'INSERT' || !record.nota || record.nota > 2) {
  return [];
}

return [{ json: { avaliacao_id: record.id, pedido_id: record.pedido_id, nota: record.nota, comentario: record.comentario || '(sem comentário)' } }];

